/*
Theme Name: Gerdes Wollmann
Author: WordPress Telex
Description: An elegant, warm block theme for the general practitioner office Gerdes & Wollmann, inspired by a garden courtyard aesthetic with cream, forest green, and amber tones.
Version: 0.1.0
Requires at least: 6.4
Tested up to: 6.8
Requires PHP: 7.4
License: GPLv2 or later
Text Domain: gerdes-wollmann
Tags: block-theme, full-site-editing, medical, elegant
*/

/* === Equal card layout === */
.equal-cards > .wp-block-column {
    display: flex;
    flex-direction: column;
    flex-grow: 0;
}
.equal-cards > .wp-block-column > .wp-block-group {
    display: flex;
    flex-direction: column;
    flex-grow: 1;
}
.equal-cards .cta-bottom {
    margin-top: auto;
    justify-content: center;
}

.wp-site-blocks > footer {
    margin-block-start: 0;
}

/* === Header divider line === */
.gw-header-divider {
    height: 1px;
    background: linear-gradient(to right, transparent, var(--wp--preset--color--amber-light), var(--wp--preset--color--dusty-rose), var(--wp--preset--color--amber-light), transparent);
    opacity: 0.5;
    margin-top: 0.5rem;
}

/* === Navigation styling === */
.gw-nav .wp-block-navigation__container {
    gap: clamp(1rem, 2.5vw, 2rem);
}
.gw-nav .wp-block-navigation-item a {
    font-weight: 500;
    font-size: clamp(0.72rem, 0.6rem + 0.3vw, 0.8rem);
    letter-spacing: 0.14em;
    text-transform: uppercase;
    text-decoration: none;
    position: relative;
    padding-bottom: 2px;
    transition: color 0.3s ease;
}
.gw-nav .wp-block-navigation-item a:hover {
    opacity: 0.75;
}
.gw-nav .wp-block-navigation-item a::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 0;
    height: 1px;
    background: currentColor;
    transition: width 0.3s ease;
}
.gw-nav .wp-block-navigation-item a:hover::after {
    width: 100%;
}

/* === Hero section === */
.gw-hero {
    min-height: min(90vh, 900px);
    position: relative;
    overflow: hidden;
}
.gw-hero::before {
    content: '';
    position: absolute;
    top: 0; left: 0; right: 0; bottom: 0;
    background:
        radial-gradient(ellipse at 15% 85%, color-mix(in srgb, var(--wp--preset--color--amber) 6%, transparent) 0%, transparent 50%),
        radial-gradient(ellipse at 80% 20%, color-mix(in srgb, var(--wp--preset--color--dusty-rose) 5%, transparent) 0%, transparent 40%);
    pointer-events: none;
    z-index: 0;
}
.gw-hero > * {
    position: relative;
    z-index: 1;
}

/* === Hero columns — intrinsic stacking === */
.gw-hero-columns {
    flex-wrap: wrap;
}
.gw-hero-columns > .wp-block-column {
    flex-basis: 0;
    flex-grow: 1;
    min-width: min(100%, 340px);
}

/* === Practice name heading === */
.gw-practice-name {
    line-height: 0.95 !important;
    letter-spacing: -0.03em;
}

/* === Subtitle label === */
.gw-subtitle {
    letter-spacing: 0.15em;
    text-transform: uppercase;
}

/* === Hours card === */
.gw-hours-card {
    position: relative;
    border: 1px solid color-mix(in srgb, var(--wp--preset--color--amber) 12%, transparent);
    border-radius: 6px;
    overflow: visible;
}
.gw-hours-card::before {
    content: '';
    position: absolute;
    top: -1px;
    left: 1.5rem;
    right: 1.5rem;
    height: 2px;
    background: linear-gradient(to right, var(--wp--preset--color--amber-light), var(--wp--preset--color--amber), var(--wp--preset--color--amber-light));
    border-radius: 2px;
}

/* === Hours row — intrinsic wrapping === */
.gw-hours-row {
    border-bottom: 1px solid color-mix(in srgb, var(--wp--preset--color--aged-paper) 70%, transparent);
    padding: 0.4rem 0;
    flex-wrap: wrap;
    gap: 0.25rem 1rem;
}
.gw-hours-row:last-child {
    border-bottom: none;
}

/* === News pins === */
.gw-news-pin {
    border-radius: 5px;
    border-left: 3px solid var(--wp--preset--color--amber);
    transform: rotate(-0.5deg);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.gw-news-pin:hover {
    transform: rotate(0deg) translateY(-2px);
    box-shadow: 0 4px 16px color-mix(in srgb, var(--wp--preset--color--forest) 12%, transparent);
}
.gw-news-pin-alt {
    border-radius: 5px;
    border-left: 3px solid var(--wp--preset--color--dusty-rose);
    transform: rotate(0.4deg);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.gw-news-pin-alt:hover {
    transform: rotate(0deg) translateY(-2px);
    box-shadow: 0 4px 16px color-mix(in srgb, var(--wp--preset--color--forest) 12%, transparent);
}

/* === News columns — intrinsic wrapping === */
.gw-news-grid {
    flex-wrap: wrap;
}
.gw-news-grid > .wp-block-column {
    flex-basis: 0;
    flex-grow: 1;
    min-width: min(100%, 300px);
}

/* === Image frame === */
.gw-image-frame {
    position: relative;
    border-radius: 8px;
    overflow: hidden;
    box-shadow:
        0 4px 20px color-mix(in srgb, var(--wp--preset--color--forest) 12%, transparent),
        0 16px 48px color-mix(in srgb, var(--wp--preset--color--forest) 10%, transparent);
}
.gw-image-frame::after {
    content: '';
    position: absolute;
    inset: 0;
    background: linear-gradient(135deg, color-mix(in srgb, var(--wp--preset--color--amber-light) 18%, transparent) 0%, color-mix(in srgb, var(--wp--preset--color--amber-light) 5%, transparent) 40%, transparent 70%);
    pointer-events: none;
    border-radius: 8px;
    z-index: 2;
}
.gw-image-frame img {
    border-radius: 8px;
    display: block;
    width: 100%;
    height: auto;
    object-fit: cover;
    aspect-ratio: 4/5;
}

/* === Contact strip — intrinsic wrapping === */
.gw-contact-strip {
    flex-wrap: wrap;
    gap: clamp(0.75rem, 2vw, 2.5rem);
    justify-content: center;
}

/* === Contact items === */
.gw-contact-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

/* === Decorative dot pattern background === */
.gw-dot-pattern::before {
    content: '';
    position: absolute;
    bottom: 10%;
    left: 2%;
    width: 80px;
    height: 80px;
    opacity: 0.12;
    background-image: radial-gradient(circle, var(--wp--preset--color--amber) 1.2px, transparent 1.2px);
    background-size: 12px 12px;
    pointer-events: none;
    z-index: 0;
}

/* === Services section cards === */
.gw-service-card {
    border-radius: 6px;
    border: 1px solid color-mix(in srgb, var(--wp--preset--color--amber) 10%, transparent);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.gw-service-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 8px 24px color-mix(in srgb, var(--wp--preset--color--forest) 10%, transparent);
}

/* === Footer columns — intrinsic wrapping === */
.gw-footer-columns {
    flex-wrap: wrap;
    gap: clamp(1.5rem, 4vw, 3rem);
}
.gw-footer-columns > .wp-block-column {
    flex-basis: 0;
    flex-grow: 1;
    min-width: min(100%, 220px);
}

/* === Footer === */
.gw-footer a {
    text-decoration: none;
    transition: opacity 0.3s ease;
}
.gw-footer a:hover {
    opacity: 0.75;
}

/* === Animations === */
@keyframes fadeInUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
}
@media (prefers-reduced-motion: no-preference) {
    .gw-hero .wp-block-columns {
        animation: fadeInUp 0.8s ease-out both;
    }
}

/* === Responsive fine-tuning === */
@media (max-width: 600px) {
    .gw-news-pin,
    .gw-news-pin-alt {
        transform: none;
    }

    .gw-hero {
        min-height: auto;
    }

    .gw-image-frame img {
        aspect-ratio: 3/4;
    }
}

{
    "$schema": "https://schemas.wp.org/trunk/theme.json",
    "version": 3,
    "settings": {
        "appearanceTools": true,
        "layout": {
            "contentSize": "860px",
            "wideSize": "1280px"
        },
        "color": {
            "palette": [
                {
                    "slug": "cream",
                    "color": "#FAF6EF",
                    "name": "Cream"
                },
                {
                    "slug": "forest",
                    "color": "#2D4A3E",
                    "name": "Forest"
                },
                {
                    "slug": "forest-light",
                    "color": "#3D6355",
                    "name": "Forest Light"
                },
                {
                    "slug": "amber",
                    "color": "#C8963E",
                    "name": "Amber"
                },
                {
                    "slug": "amber-light",
                    "color": "#E8C97A",
                    "name": "Amber Light"
                },
                {
                    "slug": "dusty-rose",
                    "color": "#C4957A",
                    "name": "Dusty Rose"
                },
                {
                    "slug": "aged-paper",
                    "color": "#EDE3D3",
                    "name": "Aged Paper"
                },
                {
                    "slug": "white",
                    "color": "#FFFFFF",
                    "name": "White"
                }
            ]
        },
        "typography": {
            "fluid": {
                "minFontSize": "13px",
                "maxViewportWidth": "1800px",
                "minViewportWidth": "320px"
            },
            "fontFamilies": [
                {
                    "fontFamily": "'Cormorant Garamond', Georgia, serif",
                    "slug": "cormorant",
                    "name": "Cormorant Garamond"
                },
                {
                    "fontFamily": "'Playfair Display', Georgia, serif",
                    "slug": "playfair",
                    "name": "Playfair Display"
                },
                {
                    "fontFamily": "'Lora', Georgia, serif",
                    "slug": "lora",
                    "name": "Lora"
                },
                {
                    "fontFamily": "'DM Sans', 'Helvetica Neue', sans-serif",
                    "slug": "dm-sans",
                    "name": "DM Sans"
                },
                {
                    "fontFamily": "'Source Serif 4', Georgia, serif",
                    "slug": "source-serif",
                    "name": "Source Serif 4"
                },
                {
                    "fontFamily": "'Libre Baskerville', Georgia, serif",
                    "slug": "libre-baskerville",
                    "name": "Libre Baskerville"
                }
            ],
            "fontSizes": [
                {
                    "slug": "small",
                    "size": "0.85rem",
                    "fluid": {
                        "min": "0.78rem",
                        "max": "0.85rem"
                    },
                    "name": "Small"
                },
                {
                    "slug": "medium",
                    "size": "1rem",
                    "fluid": {
                        "min": "0.9rem",
                        "max": "1rem"
                    },
                    "name": "Medium"
                },
                {
                    "slug": "large",
                    "size": "1.25rem",
                    "fluid": {
                        "min": "1.05rem",
                        "max": "1.25rem"
                    },
                    "name": "Large"
                },
                {
                    "slug": "x-large",
                    "size": "1.75rem",
                    "fluid": {
                        "min": "1.35rem",
                        "max": "1.75rem"
                    },
                    "name": "Extra Large"
                },
                {
                    "slug": "xx-large",
                    "size": "2.25rem",
                    "fluid": {
                        "min": "1.6rem",
                        "max": "2.25rem"
                    },
                    "name": "2X Large"
                },
                {
                    "slug": "huge",
                    "size": "3.5rem",
                    "fluid": {
                        "min": "2.2rem",
                        "max": "3.5rem"
                    },
                    "name": "Huge"
                }
            ]
        },
        "spacing": {
            "units": ["px", "em", "rem", "vh", "vw", "%"],
            "spacingSizes": [
                { "slug": "10", "size": "clamp(0.375rem, 0.75vw, 0.5rem)", "name": "XS" },
                { "slug": "20", "size": "clamp(0.75rem, 1.5vw, 1rem)", "name": "S" },
                { "slug": "30", "size": "clamp(1rem, 2.25vw, 1.5rem)", "name": "M" },
                { "slug": "40", "size": "clamp(1.5rem, 3.5vw, 2.5rem)", "name": "L" },
                { "slug": "50", "size": "clamp(2.5rem, 5.5vw, 4rem)", "name": "XL" },
                { "slug": "60", "size": "clamp(3.5rem, 8vw, 6rem)", "name": "2XL" }
            ]
        }
    },
    "styles": {
        "color": {
            "background": "var:preset|color|cream",
            "text": "var:preset|color|forest"
        },
        "typography": {
            "fontFamily": "var:preset|font-family|cormorant",
            "fontSize": "var:preset|font-size|medium",
            "lineHeight": "1.6"
        },
        "elements": {
            "heading": {
                "typography": {
                    "fontFamily": "var:preset|font-family|cormorant",
                    "fontWeight": "400",
                    "lineHeight": "1.15"
                },
                "color": {
                    "text": "var:preset|color|forest"
                }
            },
            "h1": {
                "typography": {
                    "fontSize": "var:preset|font-size|huge",
                    "fontWeight": "300"
                }
            },
            "h2": {
                "typography": {
                    "fontSize": "var:preset|font-size|xx-large",
                    "fontWeight": "400"
                }
            },
            "h3": {
                "typography": {
                    "fontSize": "var:preset|font-size|x-large",
                    "fontWeight": "500"
                }
            },
            "h4": {
                "typography": {
                    "fontSize": "var:preset|font-size|large",
                    "fontWeight": "500"
                }
            },
            "link": {
                "color": {
                    "text": "var:preset|color|amber"
                },
                ":hover": {
                    "color": {
                        "text": "var:preset|color|dusty-rose"
                    }
                }
            }
        },
        "blocks": {
            "core/navigation": {
                "typography": {
                    "fontFamily": "var:preset|font-family|cormorant",
                    "fontSize": "0.8rem",
                    "fontWeight": "500"
                }
            }
        }
    }
}

{
    "$schema": "https://schemas.wp.org/trunk/theme.json",
    "version": 3,
    "title": "Linen & Ink",
    "settings": {
        "color": {
            "palette": [
                {
                    "slug": "cream",
                    "color": "#F2EDE4",
                    "name": "Cream"
                },
                {
                    "slug": "forest",
                    "color": "#1A1A18",
                    "name": "Ink Black"
                },
                {
                    "slug": "forest-light",
                    "color": "#3A3A36",
                    "name": "Charcoal"
                },
                {
                    "slug": "amber",
                    "color": "#B8860B",
                    "name": "Dark Gold"
                },
                {
                    "slug": "amber-light",
                    "color": "#D4A84B",
                    "name": "Warm Gold"
                },
                {
                    "slug": "dusty-rose",
                    "color": "#8B7355",
                    "name": "Umber"
                },
                {
                    "slug": "aged-paper",
                    "color": "#E8DFD0",
                    "name": "Aged Paper"
                },
                {
                    "slug": "white",
                    "color": "#FAF7F2",
                    "name": "Warm White"
                }
            ]
        }
    },
    "styles": {
        "color": {
            "background": "var:preset|color|forest",
            "text": "var:preset|color|cream"
        },
        "typography": {
            "fontFamily": "var:preset|font-family|lora",
            "lineHeight": "1.65"
        },
        "elements": {
            "heading": {
                "color": {
                    "text": "var:preset|color|cream"
                },
                "typography": {
                    "fontFamily": "var:preset|font-family|playfair",
                    "fontWeight": "400",
                    "lineHeight": "1.15"
                }
            },
            "h1": {
                "typography": {
                    "fontWeight": "400",
                    "letterSpacing": "-0.02em"
                }
            },
            "h2": {
                "typography": {
                    "fontWeight": "400"
                }
            },
            "h3": {
                "typography": {
                    "fontWeight": "500"
                }
            },
            "h4": {
                "typography": {
                    "fontWeight": "500"
                }
            },
            "link": {
                "color": {
                    "text": "var:preset|color|amber-light"
                },
                ":hover": {
                    "color": {
                        "text": "var:preset|color|amber"
                    }
                }
            }
        },
        "blocks": {
            "core/navigation": {
                "typography": {
                    "fontFamily": "var:preset|font-family|lora",
                    "fontWeight": "500"
                }
            },
            "core/separator": {
                "color": {
                    "text": "var:preset|color|forest-light"
                }
            }
        }
    }
}

/**
 * Theme Assets Editor Rewrite
 *
 * This script rewrites URLs in block attributes that start with 'theme:./'
 * to point to the correct theme assets.
 * It allows blocks in templates to reference theme assets using relative paths in the editor.
**/
( function ( wp ) {
	const base = window.THEME_ASSETS_BASE_URL || '';
	const prefix = 'theme:./';

	if ( ! wp?.hooks || ! wp?.compose ) return;

	const rewrite = ( url ) => {
		if ( typeof url === 'string' && url.startsWith( prefix ) ) {
			const path = url.slice( prefix.length );
			return base + '/' + path;
		}
		return null;
	};

	wp.hooks.addFilter(
		'editor.BlockEdit',
		'theme-assets/rewrite-image-urls',
		wp.compose.createHigherOrderComponent( ( BlockEdit ) => ( props ) => {
			const { attributes } = props;
			const updates = {};

			// Check common image URL attributes
			if ( rewrite( attributes?.url ) ) {
				updates.url = rewrite( attributes.url );
			}
			if ( rewrite( attributes?.mediaUrl ) ) {
				updates.mediaUrl = rewrite( attributes.mediaUrl );
			}
			if ( rewrite( attributes?.backgroundImage ) ) {
				updates.backgroundImage = rewrite( attributes.backgroundImage );
			}

			// Pass rewritten URLs to BlockEdit for display only, without persisting changes
			if ( Object.keys( updates ).length > 0 ) {
				const modifiedProps = {
					...props,
					attributes: {
						...attributes,
						...updates,
					},
				};
				return wp.element.createElement( BlockEdit, modifiedProps );
			}

			return wp.element.createElement( BlockEdit, props );
		}, 'withThemeAssetsRewrite' )
	);

} )( window.wp );
